import anthropic
from concurrent.futures import ThreadPoolExecutor

client = anthropic.Anthropic()

def sample_at_temp(prompt: str, temperature: float) -> str:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        temperature=temperature,
        messages=[{"role": "user", "content": prompt}],
    )
    return response.content[0].text

def temperature_diverse_sample(prompt: str, temperatures: list[float] | None = None) -> list[str]:
    if temperatures is None:
        temperatures = [0.3, 0.7, 1.0, 0.5, 0.9]   # asymmetric spread

    with ThreadPoolExecutor(max_workers=len(temperatures)) as pool:
        return list(pool.map(lambda t: sample_at_temp(prompt, t), temperatures))

samples = temperature_diverse_sample(
    "What sorting algorithm should I use for nearly-sorted data? Show your reasoning."
)
# Each sample follows a different reasoning path due to temperature differences
